{% comment %} --- START: SVG Feature Icons (Flexbox Center) --- {% endcomment %}
<style>
  .svg-feature-icons-wrapper {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 15px;
    padding: 0;
    margin-top: 2px;
    color: #121212; 
  }

  .svg-feature-icon-col {
    flex: 1; 
    min-width: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
  }

  .svg-feature-icon-col svg {
    width: 22px;
    height: 22px;
    stroke: #777;
    margin-bottom: 8px; 
  }

  .svg-feature-icon-heading {
    font-family: 'Josefin Sans', sans-serif;
    font-weight: 500;
    font-size: 0.8rem; 
    margin: 0 0 3px 0; 
    word-wrap: break-word;
  }

  .svg-feature-icon-subheading {
    font-family: 'Roboto', sans-serif;
    font-size: 0.7rem; 
    color: #555; 
    margin: 0;
    word-wrap: break-word;
  }
</style>
<div class="svg-feature-icons-wrapper">

  <div class="svg-feature-icon-col">
    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5">
      <path stroke-linecap="round" stroke-linejoin="round" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
    </svg>
    <h4 class="svg-feature-icon-heading">Free shipping</h4>
  </div>

  <div class="svg-feature-icon-col">
    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5">
      <path stroke-linecap="round" stroke-linejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
    </svg>
